/**
 * PREPROCESAMIENTO FINAL — COMPATIBLE CON ESTRUCTURA N8N
 *
 * N8N ya entrega cada elemento del array original de CISA
 * como un item individual del formato:
 *
 *   items = [ {json:{...}}, {json:{...}}, ... ]
 *
 * Por lo tanto, este script SOLO debe:
 *  - Iterar sobre items[]
 *  - Normalizar cada registro
 *  - Devolver un item por cada entrada
 */

function htmlToText(html) {
    if (!html) return "";
    return String(html)
        .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
        .replace(/<\/?(br|p|div|li|ul|h\d)[^>]*>/gi, '\n')
        .replace(/<[^>]+>/g, ' ')
        .replace(/\s{2,}/g, ' ')
        .trim();
}

let output = [];

// Procesar cada item entrante
for (const item of items) {
    const r = item.json;

    let content = "";

    // Normalización de contenido
    if (r.markdown)      content = String(r.markdown);
    else if (r.text)     content = String(r.text);
    else if (r.body)     content = String(r.body);
    else if (r.html)     content = htmlToText(r.html);
    else if (r.raw)      content = String(r.raw);
    else                 content = "";

    output.push({
        json: {
            url: r.url || r.link || null,
            content,
            success: r.success === true,
            original_record: r
        }
    });
}

return output;

// ============================================================================
// SCRIPT FINAL — CURADO TWITTER (N8N READY)
// Alineado con el schema unificado para RAG y el script CISA
// ============================================================================

// Helpers
function normalizeTimestamp(ts) {
  if (!ts) return new Date().toISOString();
  const parsed = new Date(ts);
  return isNaN(parsed.getTime()) ? new Date().toISOString() : parsed.toISOString();
}

// Extract CVEs
function extractCVEs(text) {
  const regex = /\bCVE-\d{4}-\d{4,7}\b/gi;
  return text.match(regex) || [];
}

// Extract IOC (IPs, domains, urls, hashes, emails)
function extractIndicators(text) {
  const indicators = [];

  const urlRegex = /\bhttps?:\/\/[^\s)]+/gi;
  const ipRegex = /\b\d{1,3}(\.\d{1,3}){3}\b/g;
  const emailRegex = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g;
  const hashRegex = /\b[A-Fa-f0-9]{32,64}\b/g;

  const urls = text.match(urlRegex) || [];
  const ips = text.match(ipRegex) || [];
  const emails = text.match(emailRegex) || [];
  const hashes = text.match(hashRegex) || [];

  // Filtering noisy URLs: remove twitter internal tracking, t.co, media, and CISA if present
  const blacklistPatterns = [
    "https://t.co/",
    "https://x.com/",
    "twitter.com",
    "pbs.twimg.com",
    "cisa.gov",            // internal to CISA, not an IOC
  ];

  urls.forEach(u => {
    if (!blacklistPatterns.some(b => u.includes(b))) {
      indicators.push({ type: "url", value: u });
    }
  });

  ips.forEach(ip => indicators.push({ type: "ip", value: ip }));
  emails.forEach(e => {
    // Filter CISA internal emails
    if (!e.endsWith("@cisa.gov")) {
      indicators.push({ type: "email", value: e });
    }
  });
  hashes.forEach(h => indicators.push({ type: "hash", value: h }));

  return indicators;
}

// Confidence scoring
function assignConfidence(indType, cves, isCTI) {
  if (isCTI) return 100; // Highest
  if (indType === "cve" && cves.length > 0) return 90;
  if (["ip", "domain", "hash", "url", "email"].includes(indType)) return 70;
  return 30; // informational
}

// MITRE ATT&CK TTP generator
function generateTTP(text, isCTI) {
  if (!isCTI) return [];

  const ttp = [];

  const map = [
    { pattern: /ransomware/i, t: "TA0040" },
    { pattern: /apt/i, t: "TA0010" },
    { pattern: /lateral/i, t: "T1021" },
    { pattern: /persistence/i, t: "T1053" },
    { pattern: /credential/i, t: "T1555" },
    { pattern: /c2|command and control/i, t: "T1071" },
    { pattern: /exfiltration/i, t: "T1041" }
  ];

  for (const entry of map) {
    if (entry.pattern.test(text)) ttp.push(entry.t);
  }

  if (ttp.length === 0) ttp.push("TA0001"); // default CTI baseline

  return ttp;
}

// ============================================================================
// PROCESS INPUT
// ============================================================================

const input = items[0].json.tweets;    // Using your real structure
const outputs = [];

for (const tw of input) {

  const text = tw.text || "";
  const created = tw.createdAt || null;
  const author = tw.author || {};

  // Extract CVEs
  const cves = extractCVEs(text);

  // Determine CTI classification
  const isCTI = /ransomware|apt|threat/i.test(tw.text);

  // Extract IOC
  const rawIndicators = extractIndicators(text);

  // Add CVE indicators
  cves.forEach(cve => rawIndicators.push({ type: "cve", value: cve }));

  // If nothing extracted, add informational indicator
  if (rawIndicators.length === 0) {
    rawIndicators.push({
      type: "informational",
      value: "no_ioc_detected"
    });
  }

  // Build final indicators array with confidence
  const indicators = rawIndicators.map(ind => ({
    type: ind.type,
    value: ind.value,
    confidence: assignConfidence(ind.type, cves, isCTI)
  }));

  // Generate TTPs
  const ttps = generateTTP(text, isCTI);

  // Build unified record
  const unified = {
    id: tw.id,
    source: "twitter",
    source_url: tw.url || tw.twitterUrl || null,

    ingest_timestamp: new Date().toISOString(),
    published_timestamp: normalizeTimestamp(created),

    title: null,
    text: text,
    summary: null,

    cves: cves,
    indicators: indicators,
    ttps: ttps,
    tags: ["osint", "threat", "twitter"],

    author: {
      name: author.name || null,
      id: author.id || null,
      type: author.type || "user",
      profile_url: author.url || null
    },

    references: (tw.entities?.urls || []).map(u => u.expanded_url).filter(Boolean),

    raw: {
      content: text
    },

    provenance: {
      ingested_from_file: "TWITTER_Extract.json",
      original_record_id: tw.id
    }
  };

  outputs.push({ json: unified });
}

return outputs;

/**
 * Nodo de Deduplicación y Normalización de Ciberseguridad
 * Objetivo: Preservar IDs originales y generar un UniqueID mediante SHA-256
 * para evitar duplicados en Qdrant durante ejecuciones cada 15 minutos.
 */

const crypto = require('crypto');

return items.map(item => {
    const record = item.json;

    // 1. Preservar el ID original del archivo JSON (Twitter o CISA)
    const originalId = record.id || "sin_id";
    const sourceUrl = record.source_url || "";

    // 2. Crear la semilla para el hash combinando record.id y record.source_url
    // Esto asegura que si el mismo ID aparece en URLs distintas, se traten por separado
    const combinedKey = `${originalId}${sourceUrl}`;

    // 3. Generar el UniqueID mediante SHA-256
    // Usamos el módulo 'crypto' habilitado previamente en tu Docker
    const uniqueID = crypto.createHash('sha256')
                           .update(combinedKey)
                           .digest('hex');

    // 4. Construir el objeto JSON resultante para Qdrant
    return {
        json: {
            // El 'id' para Qdrant será nuestro nuevo UniqueID (hexadecimal)
            id: uniqueID, 
            id_original: originalId, // Preservamos el ID original del origen (X/CISA)

            // Contenido principal para el embedding de Mistral
            text: record.text,
            title: record.title || "Aviso de Ciberseguridad",

            // Metadatos enriquecidos para el filtrado RAG
            metadata: {
                source: record.source,
                source_url: sourceUrl,
                published_at: record.published_timestamp,
                ingest_timestamp: new Date().toISOString(),

                // Campos específicos de amenazas para análisis posterior
                cves: record.cves || [],
                indicators: record.indicators || [],
                ttps: record.ttps || [],
                author: record.author || [],
                references: record.references || [],
                tags: record.tags || []
            }
        }
    };
});

// 1. Acceder a todos los ítems de entrada (n8n v1+)
const inputItems = $input.all();

// 2. Configuración de filtrado
const baseUrl = "https://www.incibe.es/en/incibe-cert/notices/aviso/";
const excludedExact = [
  "https://www.incibe.es/index.php/en/incibe-cert",
  "https://www.incibe.es/en/"
];

/** @type {Array<{json: any, pairedItem?: {item: number}}>} */
const output = [];
const uniqueHrefs = new Set();

// --- FUNCIÓN DE BÚSQUEDA RECURSIVA ---
// Esta función recorre todo el JSON buscando llaves llamadas 'href'
function findHrefs(obj) {
  let found = [];
  if (!obj || typeof obj !== 'object') return found;

  if (Array.isArray(obj)) {
    obj.forEach(item => {
      found = found.concat(findHrefs(item));
    });
  } else {
    for (const key in obj) {
      if (key === 'href' && typeof obj[key] === 'string') {
        found.push(obj[key]);
      } else {
        found = found.concat(findHrefs(obj[key]));
      }
    }
  }
  return found;
}

// 3. Procesar cada ítem de entrada
inputItems.forEach((item, itemIndex) => {
  // Extraemos todos los hrefs posibles del JSON sin importar la ruta
  const allHrefsInItem = findHrefs(item.json);

  allHrefsInItem.forEach(rawHref => {
    let href = rawHref.trim();

    // Convertir rutas relativas a absolutas si es necesario
    if (href.startsWith("/")) {
      href = "https://www.incibe.es/en/incibe-cert/notices/aviso/" + href;
    }

    // --- LÓGICA DE FILTRADO ---
    // A. Debe empezar con la base de noticias de seguridad
    if (href.startsWith(baseUrl)) {

      // B. No debe ser una URL de navegación exacta (Home, Index, Feed)
      const isExactMatch = excludedExact.some(exc => href === exc || href === exc + "/");

      // C. No debe ser una página de paginación (/page/2, etc.)
      const isPagination = href.includes("/page/");

      if (!isExactMatch && !isPagination && !uniqueHrefs.has(href)) {
        uniqueHrefs.add(href);

        output.push({
          json: {
            href: href,
            source: "incibe-cert_aviso",
            extracted_at: new Date().toISOString()
          },
          pairedItem: {
            item: itemIndex
          }
        });
      }
    }
  });
});

// 4. Garantizar salida de datos (Fallback para que el flujo no se detenga)
if (output.length === 0) {
  return [{
    json: {
      href: null,
      source: "incibe-cert_aviso",
      message: "No se encontraron enlaces válidos. Verifica que el JSON de entrada contenga propiedades 'href'.",
      debug_info: {
        items_processed: inputItems.length,
        first_item_keys: inputItems[0] ? Object.keys(inputItems[0].json) : 'none'
      },
      extracted_at: new Date().toISOString()
    }
  }];
}

return output;

const crypto = require('crypto');

// 1. Extract content from the incoming n8n item
const item = $input.first().json;
const markdown = item.data || "";

// 2. Isolate Key Sections: Insights (4), Next Steps (5), and Artifacts (3)
const insightsMatch = markdown.match(/### 4\. Key Insights\s*\n([\s\S]*?)(?=\n###|$)/);
const nextStepsMatch = markdown.match(/### 5\. Next Steps\s*\n([\s\S]*?)(?=\n###|$)/);
const artifactsMatch = markdown.match(/### 3\. Investigation Artifacts\s*\n([\s\S]*?)(?=\n###|$)/);

if (!insightsMatch || !nextStepsMatch) return [];

const insights = insightsMatch[1].trim().split(/\n\d+\.\s+/).filter(i => i.trim() !== "");
const nextSteps = nextStepsMatch[1].trim().split(/\n-\s+/).filter(n => n.trim() !== "");
const artifactsContent = artifactsMatch ? artifactsMatch[1].toLowerCase() : "";

// 3. TTP Mapping Logic
const ttpMap = {
    "ransomware": "T1486",
    "phishing": "T1566",
    "obfuscation": "T1027",
    "exfiltration": "T1020"
};

const globalTtps = Object.keys(ttpMap)
    .filter(keyword => artifactsContent.includes(keyword))
    .map(keyword => ttpMap[keyword]);

const curatedData = [];

// 4. Process items by matching index
insights.forEach((insightRaw, index) => {
    const insightParts = insightRaw.match(/^\*\*(.*?)\*\*:\s+([\s\S]*)/);
    if (!insightParts) return;

    const title = insightParts[1].trim();
    const insightText = insightParts[2].trim();
    const nextStepText = nextSteps[index] ? nextSteps[index].trim() : "";
    const mergedText = `INSIGHT: ${insightText}\n\nOPERATIONAL ACTION: ${nextStepText}`;

    // 5. FIXED ONION REGEX: Optional protocol handler
    const onionRegex = /(?:http[s]?:\/\/)?([a-z2-7]{56}\.onion[^\s\)]*)/i;
    const foundOnion = nextStepText.match(onionRegex);
    let sourceUrl = "http://robin.internal/analysis";
    if (foundOnion) {
        let rawUrl = foundOnion[0].replace(/[,\.\)]+$/, "");
        sourceUrl = rawUrl.startsWith('http') ? rawUrl : `http://${rawUrl}`;
    }

    // 6. FIXED CVE & INDICATOR PARSING
    // Standard CVE Regex: CVE-YEAR-ID
    const cveRegex = /CVE-\d{4}-\d{4,7}/gi;
    const extractedCves = [...new Set(mergedText.match(cveRegex) || [])].map(c => c.toUpperCase());

    // Generate indicators array based on found CVEs
    const indicators = extractedCves.map(cve => ({
        type: "cve",
        value: cve,
        confidence: 90
    }));

    // 7. Final JSON Construction matching CISA/Twitter Schema
    curatedData.push({
        json: {
            id: crypto.createHash('sha256').update(mergedText).digest('hex'),
            id_original: `robin::insight::${index + 1}`,
            text: mergedText,
            title: title,
            source: "robin_darkweb",
            source_url: sourceUrl, 
            published_at: new Date().toISOString(),
            ingest_timestamp: new Date().toISOString(),
            cves: extractedCves, // Will be [] if none found
            indicators: indicators, // Will be [] if none found
            ttps: [...new Set([
                ...globalTtps,
                ...(insightText.toLowerCase().includes('ransomware') ? ["T1486"] : [])
            ])],
            author: {
                name: "Robin Intelligence Agent",
                id: "ROBIN_OSINT",
                type: "bot"
            },
            tags: ["osint", "threat", "darkweb", "targeted_discussion"]
        }
    });
});

return curatedData;

const crypto = require('crypto');

// 1. Obtener todos los elementos de entrada
const items = $input.all();
const curatedData = [];

// Mapeo dinámico de TTPs basado en palabras clave del cuerpo del aviso
const ttpMap = {
    "cross-site scripting": "T1059.007",
    "xss": "T1059.007",
    "ransomware": "T1486",
    "phishing": "T1566",
    "escalada de privilegios": "T1068",
    "privilege escalation": "T1068",
    "denegación de servicio": "T1498",
    "denial of service": "T1498"
};

items.forEach((item) => {
    // 2. Acceso a la estructura 'body' definida en el requerimiento
    const body = item.json.body;
    if (!body || !body.success) return;

    const markdown = body.markdown || "";
    const sourceUrl = body.url || "";

    // 3. Extracción de Títulos (asumimos la primera línea del markdown o título de la plataforma)
    const titleMatch = markdown.match(/# (.*)/);
    const title = titleMatch ? titleMatch[1].trim() : "INCIBE-CERT Security Advisory";

    // 4. Extracción de CVEs (Regex global)
    const cveRegex = /CVE-\d{4}-\d{4,7}/gi;
    const extractedCves = [...new Set(markdown.match(cveRegex) || [])].map(c => c.toUpperCase());

    // 5. Identificación de TTPs
    const detectedTtps = Object.keys(ttpMap)
        .filter(keyword => markdown.toLowerCase().includes(keyword))
        .map(keyword => ttpMap[keyword]);

    // 6. Normalización al esquema curado para Qdrant
    curatedData.push({
        json: {
            id: crypto.createHash('sha256').update(markdown + sourceUrl).digest('hex'),
            id_original: `incibe::${crypto.createHash('md5').update(sourceUrl).digest('hex')}`,
          source: "incibe_cert",
          source_url: sourceUrl, // Mapeo solicitado: body.url -> source_url            
            text: markdown, // Mapeo solicitado: Markdown -> Text
            title: title,
            ingest_timestamp: new Date().toISOString(),
            published_at: new Date().toISOString(), // INCIBE suele tenerlo en metadata, se usa fallback
            metadata: {
                source: "incibe_cert",
                source_url: sourceUrl,
                cves: extractedCves,
                indicators: extractedCves.map(cve => ({
                    type: "cve",
                    value: cve,
                    confidence: 95
                })),
                ttps: [...new Set(detectedTtps)],
                author: {
                    name: "INCIBE-CERT",
                    id: "INCIBE",
                    type: "agency",
                    profile_url: "https://www.incibe.es/en/incibe-cert"
                },
                tags: ["osint", "threat", "vulnerability", "incibe", "cert_es"]
            }
        }
    });
});

return curatedData;

/**
 * SCRIPT FINAL CISA — CURADO COMPLETO (CON CTI + TTPs MITRE)
 *
 * Entrada esperada (items[]): cada item.json debe venir del preprocesador y tener:
 *   { url: "...", content: "markdown completo extraído", success: true, ... }
 *
 * Salida: un item por cada advisory con la estructura unificada:
 *   {
 *     id, source, source_url,
 *     ingest_timestamp, published_timestamp,
 *     title, text, summary,
 *     cves, indicators, ttps, tags,
 *     author, references, raw, provenance
 *   }
 *
 * Cambios clave incorporados:
 * - extracción SOLO del contenido relevante del advisory (quita header/footer/menu)
 * - extracción de CVEs, TTPs ATT&CK, IoCs (IPs, urls, domains, emails, hashes)
 * - filtros: eliminar urls/emails de cisa.gov, mitre/nvd/nist/cve.org
 * - nuevo indicator "cti" (confidence 100) si el título contiene ransom/apt/threat
 * - generación automática de TTPs MITRE según tipo CTI (ransomware / apt / threat)
 * - escala de confidence actualizada (cti>cve>...)
 * - indicador "informational" (confidence baja) cuando no hay IoCs técnicos o advisory guidance
 *
 * Comentarios detallados sobre timestamps y confidence están incluidos en el bloque correspondiente.
 */


/* ============================
   UTILIDADES BÁSICAS
   ============================ */

function uuid() {
  // Genera un id simple único (no criptográfico)
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

/* Normaliza una fecha de texto a ISO. Si no puede parsear, devuelve fallback (string ISO). */
function normalizeTimestamp(raw, fallback) {
  if (!raw || typeof raw !== 'string') return fallback;
  const p = Date.parse(raw);
  if (!isNaN(p)) return new Date(p).toISOString();
  return fallback;
}

/* Devuelve hora actual en ISO (UTC). Usamos UTC para consistencia entre nodos/entornos. */
function nowIso() {
  return (new Date()).toISOString();
}


/* ============================
   EXTRACCIÓN DEL CONTENIDO RELEVANTE
   ============================ */

/**
 * extractRelevantText(markdown)
 * - Toma el markdown completo y devuelve SOLO el cuerpo relevante del advisory.
 * - Estrategia:
 *   1) Buscar el título H1 (# ...) y recortar todo lo anterior.
 *   2) Cortar secciones finales comunes (Please share..., Related Advisories, footer).
 *   3) Reemplazar links markdown [txt](url) -> txt.
 *   4) Limpiar markdown básico (negrillas/italicas y espacios repetidos).
 */
function extractRelevantText(markdown) {
  if (!markdown) return '';

  let text = String(markdown);

  // 1) arrancar desde H1 si existe
  const titleMatch = text.match(/^#\s+.+/m);
  if (titleMatch) {
    const idx = text.indexOf(titleMatch[0]);
    if (idx >= 0) text = text.slice(idx);
  }

  // 2) cortar secciones institucionales comunes al final
  const hardStops = [
    '## Please share your thoughts',
    '## Related Advisories',
    'Cybersecurity & Infrastructure Security Agency',
    'An official website of the U.S. Department of Homeland Security',
    'Website Feedback',
    'About CISA'
  ];
  for (const stop of hardStops) {
    const i = text.indexOf(stop);
    if (i !== -1) text = text.slice(0, i);
  }

  // 3) reemplazar links markdown por texto visible
  text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

  // 4) limpieza básica
  text = text
    .replace(/\*\*/g, '')
    .replace(/_/g, '')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();

  return text;
}


/* ============================
   REGEX / EXTRACTORS
   ============================ */

const cveRegex    = /\bCVE-\d{4}-\d{4,7}\b/gi;
const ttpRegex    = /\bT\d{4}(?:\.\d{3})?\b/g;
const ipRegex     = /\b(?:(?:25[0-5]|2[0-4]\d|1?\d{1,2})\.){3}(?:25[0-5]|2[0-4]\d|1?\d{1,2})\b/g;
const emailRegex  = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g;
const urlRegex    = /\bhttps?:\/\/[^\s"')]+/gi;
const domainRegex = /\b([a-zA-Z0-9-]+\.)+(com|org|net|gov|edu|io|info|biz|us|uk)\b/gi;
const hashRegex   = /\b[a-f0-9]{32}\b|\b[a-f0-9]{40}\b|\b[a-f0-9]{64}\b/gi;

/* devuelve array único */
function extractUnique(regex, text) {
  if (!text) return [];
  const m = text.match(regex) || [];
  return Array.from(new Set(m));
}

function extractCVEs(text) {
  return extractUnique(cveRegex, text).map(c => c.toUpperCase());
}
function extractTTPs(text) {
  return extractUnique(ttpRegex, text);
}
function extractIndicatorsRaw(text) {
  return {
    ips:    extractUnique(ipRegex, text),
    urls:   extractUnique(urlRegex, text),
    domains: extractUnique(domainRegex, text).map(s => s.toLowerCase()),
    emails: extractUnique(emailRegex, text),
    hashes: extractUnique(hashRegex, text)
  };
}


/* ============================
   LISTAS NEGRAS (CISA, CVE/MITRE/NIST)
   ============================ */

const cisaDomainsBlacklist = [
  'cisa.gov', 'www.cisa.gov'
];
const cisaEmailsBlacklist = [
  '@cisa.gov'
];
const cveDomainsBlacklist = [
  'cve.org', 'nvd.nist.gov', 'nist.gov', 'mitre.org'
];
const cveEmailsBlacklist = [
  '@mitre.org', '@nist.gov'
];

/* filtro de url: cualquier url que contenga cisa.gov o dominios CVE oficiales */
function isBlacklistedUrl(url) {
  if (!url) return false;
  const u = String(url).toLowerCase();
  if (u.includes('cisa.gov')) return true;
  for (const d of cveDomainsBlacklist) if (u.includes(d)) return true;
  return false;
}
function isBlacklistedEmail(email) {
  if (!email) return false;
  const e = String(email).toLowerCase();
  for (const s of cisaEmailsBlacklist) if (e.endsWith(s)) return true;
  for (const s of cveEmailsBlacklist) if (e.endsWith(s)) return true;
  return false;
}


/* ============================
   CONFIDENCE (ESCALA RE-ESCALEADA)
   ============================
   Nueva prioridad: CTI (max) > CVE > hash > ip > domain > url > email > informational
   - CTI: 100
   - CVE: 95
   - hash:90
   - ip:85
   - domain:80
   - url:70
   - email:50
   - informational:10
   - default:30
*/
function confidence(type) {
  switch ((type||'').toLowerCase()) {
    case 'cti': return 100;
    case 'cve': return 95;
    case 'hash': return 90;
    case 'ip': return 85;
    case 'domain': return 80;
    case 'url': return 70;
    case 'email': return 50;
    case 'informational': return 10;
    default: return 30;
  }
}

/* ============================
   DETECCIÓN DE CTI Y GENERACIÓN DE TTPs MITRE
   ============================ */

/* determina si el advisory es CTI por título */
function isCTIAdvisory(title) {
  if (!title) return false;
  const t = title.toLowerCase();
  return t.includes('ransomware') || t.includes('apt') || t.includes('threat');
}

/* función que mapea títulos CTI a TTPs MITRE relevantes */
function generateCTITTPs(title) {
  if (!title) return [];
  const t = title.toLowerCase();
  if (t.includes('ransomware')) {
    return [
      'T1486', // Data Encrypted for Impact
      'T1059', // Command and Scripting Interpreter
      'T1569', // System Services (Service Execution)
      'T1027', // Obfuscated Files or Information
      'T1041', // Exfiltration Over C2
      'T1078', // Valid Accounts
      'T1047'  // Windows Management Instrumentation
    ];
  }
  if (t.includes('apt')) {
    return [
      'T1059', // Command Execution
      'T1071', // Application Layer Protocol
      'T1105', // Ingress Tool Transfer
      'T1082', // System Information Discovery
      'T1566', // Phishing (Spearphishing)
      'T1003', // Credential Dumping
      'T1041'  // Exfiltration Over C2
    ];
  }
  if (t.includes('threat')) {
    return [
      'T1595', // Active Scanning
      'T1592', // Gather Victim Identity Info
      'T1608', // Stage Capabilities
      'T1598', // Phishing for Information
      'T1057', // Process Discovery
      'T1018'  // Remote System Discovery
    ];
  }
  return [];
}

/* crea indicador CTI */
function makeCTIIndicator() {
  return {
    type: 'cti',
    value: 'threat-intel',
    confidence: confidence('cti')
  };
}

/* ============================
   'informational' helper
   ============================ */
function isInformationalAdvisoryTitle(title) {
  if (!title) return false;
  const t = title.toLowerCase();
  const keywords = ['guidance', 'control', 'controls', 'best practice', 'best practices', 'mitigation', 'checklist', 'recommendation', 'recommendations', 'guidelines', 'overview'];
  return keywords.some(k => t.includes(k));
}
function makeInformationalIndicator() {
  return { type: 'informational', value: 'context', confidence: confidence('informational') };
}

/* ============================
   AUTO TAGS (heurísticos)
   ============================ */
function autoTags(text) {
  if (!text) return ['osint'];
  const t = text.toLowerCase();
  const tags = new Set(['osint', 'threat']);
  if (t.includes('vulnerability') || t.includes('cve')) tags.add('vulnerability');
  if (t.includes('exploit')) tags.add('exploit');
  if (t.includes('ransomware')) tags.add('ransomware');
  if (t.includes('malware')) tags.add('malware');
  if (t.includes('phishing')) tags.add('phishing');
  if (t.includes('ics')) tags.add('ics');
  if (t.includes('known exploited') || t.includes('kev')) tags.add('kev');
  if (t.includes('patch') || t.includes('update')) tags.add('patching');
  return Array.from(tags);
}


/* ============================
   PROCESAMIENTO PRINCIPAL (uno-a-uno)
   ============================ */

const output = [];

for (const item of items) {
  // item.json viene del preprocesador
  const rec = item.json || {};
  const rawOriginal = rec.content || '';       // guardamos el markdown completo en raw.content
  const raw = extractRelevantText(rawOriginal); // texto reducido y relevante (usar para extracción)
  const source_url = rec.url || null;

  // TITULO extraído del H1 (si existe) o del slug de la URL
  let title = null;
  const titleMatch = raw.match(/^#\s*(.+)/m);
  if (titleMatch) title = titleMatch[1].trim();
  else if (source_url) {
    const slug = source_url.split('/').filter(Boolean).pop() || null;
    title = slug ? slug.replace(/[-_]+/g, ' ') : null;
  }

  // TIMESTAMPS
  // ingest_timestamp: momento en que el curador ingiere el registro (ISO UTC)
  const ingest_timestamp = nowIso();

  // published_timestamp: intentamos parsear alguna fecha en el texto (no siempre presente)
  // Estrategia: no hay heurística de "Release Date" adicional aquí por simplicidad; fallback = ingest_timestamp.
  // Si quieres, podemos añadir heurísticos más complejos para extraer fechas.
  let published_timestamp = ingest_timestamp; // fallback
  // (opcional) intentar detectar fechas en texto - simple regex (YYYY-MM-DD)
  const isoDateMatch = raw.match(/\b(20\d{2}-\d{2}-\d{2})\b/);
  if (isoDateMatch) {
    published_timestamp = normalizeTimestamp(isoDateMatch[1], ingest_timestamp);
  }

  // EXTRAER CVEs, TTPs, INDICADORES (raw)
  const cves = extractCVEs(raw);               // CVEs canonizados
  let ttps = extractTTPs(raw);                 // TTPs explícitos en texto
  const indicatorsRaw = extractIndicatorsRaw(raw);

  // Construir indicadores a partir de lo extraído (antes de filtrar)
  let indicators = [];

  (indicatorsRaw.ips || []).forEach(ip => indicators.push({ type: 'ip', value: ip, confidence: confidence('ip') }));
  (indicatorsRaw.urls || []).forEach(u => indicators.push({ type: 'url', value: u, confidence: confidence('url') }));
  (indicatorsRaw.domains || []).forEach(d => indicators.push({ type: 'domain', value: d, confidence: confidence('domain') }));
  (indicatorsRaw.emails || []).forEach(e => indicators.push({ type: 'email', value: e, confidence: confidence('email') }));
  (indicatorsRaw.hashes || []).forEach(h => indicators.push({ type: 'hash', value: h, confidence: confidence('hash') }));
  (cves || []).forEach(c => indicators.push({ type: 'cve', value: c, confidence: confidence('cve') }));

  // FILTRADO: eliminar URLs/Domains/Emails que sean feedback / institucionales de CISA o referencias CVE oficiales
  indicators = indicators.filter(ind => {
    if (!ind || !ind.type || !ind.value) return false;
    const val = String(ind.value).toLowerCase();

    // URLs y dominios: eliminar si contienen cisa.gov o dominios CVE oficiales
    if (ind.type === 'url' || ind.type === 'domain') {
      if (val.includes('cisa.gov')) return false;
      for (const d of cveDomainsBlacklist) if (val.includes(d)) return false;
    }

    // Emails: eliminar si terminan con @cisa.gov o dominios CVE relacionados
    if (ind.type === 'email') {
      for (const s of cisaEmailsBlacklist) if (val.endsWith(s)) return false;
      for (const s of cveEmailsBlacklist) if (val.endsWith(s)) return false;
    }

    return true;
  });

  // DETECCION CTI (por título) -> si true, inyectar indicador CTI y generar TTPs MITRE
  const isCTI = isCTIAdvisory(title || '');

  if (isCTI) {
    // agregar indicador CTI (confidence 100)
    indicators.push(makeCTIIndicator());

    // generar TTPs MITRE asociados al tipo (ransomware | apt | threat)
    const generated = generateCTITTPs(title || '');
    if (Array.isArray(generated) && generated.length > 0) {
      // añadir TTPs generados si no están ya presentes
      for (const t of generated) if (!ttps.includes(t)) ttps.push(t);
    }
  }

  // Lógica para "informational" si NO hay indicadores técnicos (ip/domain/url/hash/cve/email)
  const hasTechnicalIndicators = indicators.some(ind => ['ip','domain','url','hash','cve','email'].includes((ind.type||'').toLowerCase()));

  // Si no es CTI (CTI tiene prioridad), y no hay indicadores técnicos o el título indica guidance -> informational
  if (!isCTI) {
    if (!hasTechnicalIndicators || isInformationalAdvisoryTitle(title || '')) {
      indicators.push(makeInformationalIndicator());
    }
  }

  // (Opcional) si existen indicadores duplicados, eliminar duplicados por type+value
  const dedup = {};
  indicators = indicators.filter(ind => {
    const k = (ind.type||'') + '::' + (String(ind.value||''));
    if (dedup[k]) return false;
    dedup[k] = true;
    return true;
  });

  // TITLE final (si no existía anteriormente)
  let finalTitle = title;
  if (!finalTitle && source_url) {
    finalTitle = source_url.split('/').filter(Boolean).pop() || null;
  }

  // REFERENCES: tomar urls no filtradas encontradas en rawOriginal (pueden ser útiles)
  const allUrls = extractUnique(urlRegex, rawOriginal);
  const references = (allUrls || []).filter(u => !isBlacklistedUrl(u));

  // SUMMARY: primer párrafo o primeros 240 caracteres
  let summary = null;
  if (raw) {
    const firstPara = raw.split(/\n{1,}/).find(p => p.trim().length > 0) || raw;
    summary = firstPara.length > 240 ? firstPara.slice(0,237).trim() + '...' : firstPara.trim();
  }

  // ENSAMBLAR OBJETO UNIFICADO
  const unified = {
    id: 'cisa::' + uuid(),
    source: 'cisa',
    source_url: source_url,

    // ingest_timestamp: aplicamos hora local del sistema en ISO (UTC used here)
    ingest_timestamp: ingest_timestamp,

    // published_timestamp: si no puede derivarse se deja igual al ingest_timestamp (fallback)
    published_timestamp: published_timestamp || ingest_timestamp,

    title: finalTitle || null,
    text: raw || '',
    summary: summary || null,

    cves: cves || [],

    indicators: indicators || [],

    ttps: ttps || [],

    tags: autoTags(raw),

    author: {
      name: 'Cybersecurity and Infrastructure Security Agency',
      id: 'CISA',
      type: 'agency',
      profile_url: 'https://www.cisa.gov/'
    },

    references: references || [],

    raw: {
      content: rawOriginal   // preservamos el markdown original sin recortar
    },

    provenance: {
      ingested_from_file: 'CISA_Markdown.json',
      original_record_id: source_url || null
    }
  };

  output.push({ json: unified });
}

/* Si por alguna razón no se procesó nada, devolvemos un warning ITEM para no romper n8n */
if (output.length === 0) {
  return [{ json: { warning: 'No records processed by CISA curador' } }];
}

return output;
